B.a0c=new A.aL("Schalte neue Level und Herausforderungen frei, indem du im Spiel fortschreitest.",null,null,null,null,null,null,null,null,null)
B.a0e=new A.aL("8.\tStartbildschirm: ",null,B.bp,null,null,null,null,null,null,null)
B.a0d=new A.aL("Bist du sicher, dass du das Level abbrechen wollen?",null,null,null,null,null,null,null,null,null)
B.a0g=new A.aL("Fortune Wheel",null,null,null,null,null,null,null,null,null)
B.a0h=new A.aL("Diese Studie diente dem Erfassen von nat\xfcrlichem Spielverhalten bei Handy/Tabletspielen und dem Einfluss sogenannter Dark Patterns. Unter Dark Patterns versteht man Features/Eigenschaften des Spiels, die dazu dienen sollen, den Spieler zu h\xe4ufigerem oder l\xe4ngerem Spielen zu animieren oder Geld f\xfcr oder im Spiel auszugeben. Mit deiner Teilnahme leistest du einen wichtigen Beitrag dazu, den Einfluss solcher Dark Patterns noch genauer zu verstehen. Damit k\xf6nnen Spieler in Zukunft besser \xfcber deren Auswirkungen aufgekl\xe4rt und das Spielen solcher Spiele sicherer gestaltet werden.",null,null,null,null,null,null,null,null,null)
B.a0i=new A.aL("7.\tFortschritt und Herausforderungen: ",null,B.bp,null,null,null,null,null,null,null)
