B.a0j=new A.aL("T\xe4gliche Belohnung bereits abgeholt",null,null,null,null,null,null,null,null,null)
B.a0k=new A.aL("Vielen Dank f\xfcr Ihr Interesse an unserer Studie. Leider d\xfcrfen aus rechtlichen Gr\xfcnden nur Personen mit einem Mindestalter von 18 Jahren an unsere Studie teilnehmen.",null,null,null,null,null,null,null,null,null)
B.a0l=new A.aL("Dr\xfccken Sie auf den \u201eTeilen\u201c-Button (kleine Viereck mit dem Pfeil nach oben) -> Option -> zum Home-Bildschirm",null,B.dm,B.L,null,null,null,null,null,null)
B.a0m=new A.aL("Viel Spa\xdf beim Spielen!\n          ",null,B.bp,null,null,null,null,null,null,null)
B.Cb=new A.aL("Keine Z\xfcge mehr m\xf6glich",null,null,null,null,null,null,null,null,null)
B.a0n=new A.aL("Nicht genug M\xfcnzen um dieses PowerUp zu kaufen",null,null,null,null,null,null,null,null,null)
B.a0o=new A.aL("5.\tBewegungsbegrenzung und Zeitlimit: ",null,B.bp,null,null,null,null,null,null,null)
B.a0p=new A.aL("Jedes Level hat spezifische Ziele, wie das Erreichen einer bestimmten Punktzahl, das Sammeln einer Anzahl von bestimmten Jellies oder das Entfernen von Hindernissen. Das jeweilige Ziel wird in dem Kasten rechts oben auf dem Bildschirm angezeigt\n              ",null,null,null,null,null,null,null,null,null)
B.a0q=new A.aL("Du hast nicht genug M\xfcnzen um dieses Level freizuschalten",null,null,null,null,null,null,null,null,null)
B.a0t=new A.aL("Einige Level haben eine begrenzte Anzahl von Z\xfcgen oder ein Zeitlimit, um die Ziele zu erreichen. Dies wird in dem Kasten links oben auf dem Bildschirm angezeigt.\n          ",null,null,null,null,null,null,null,null,null)
